async function main() {
  const scoreStream = connectWebSocket('ws://game-scores-stream');
  const playerScores: Record<string, number> = {};
  let lastLeaderboardJson = '';

  for await (const event of scoreStream) {
    const { playerId, score } = event;
    playerScores[playerId] = score;

    const top10 = Object.entries(playerScores)
      .map(([playerId, score]) => ({ playerId, score }))
      .sort((a, b) => b.score - a.score)
      .slice(0, 10);

    const currentLeaderboardJson = JSON.stringify(top10);

    if (currentLeaderboardJson !== lastLeaderboardJson) {
      lastLeaderboardJson = currentLeaderboardJson;
      await sendPushNotification(`Leaderboard Update: ${currentLeaderboardJson}`);
    }
  }
}
