async function getPricingWithRetry(apiUrl: string, cachePath: string): Promise<any> {
  let attempt = 0;
  const maxRetries = 3;

  while (attempt <= maxRetries) {
    try {
      const data = await fetchFromApi(apiUrl);

      // Update cache on success
      await writeFile(cachePath, JSON.stringify(data));
      await logToAudit({ url: apiUrl, attempt, status: 'success' });

      return data;
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      await logToAudit({ url: apiUrl, attempt, status: 'failure', error: errorMessage });

      if (attempt < maxRetries) {
        // Exponential backoff: 1s, 2s, 4s
        const delay = Math.pow(2, attempt) * 1000;
        await new Promise((resolve) => setTimeout(resolve, delay));
        attempt++;
      } else {
        // All retries exhausted, fallback to cache
        await logToAudit({ url: apiUrl, attempt, status: 'retries_exhausted', action: 'fallback_to_cache' });
        const cachedContent = await readFile(cachePath);
        return JSON.parse(cachedContent);
      }
    }
  }
}
