async function main() {
  const queueUrl = 'https://api.jobs.queue/stream';
  const dlqTable = 'dead_letter_queue';
  const opsChannel = '#ops-alerts';
  const pollInterval = 5000;

  for await (const message of pollSource(queueUrl, pollInterval)) {
    let attempts = 0;
    let lastError: any = null;
    let success = false;

    // Initial attempt + up to 2 retries = 3 total attempts
    while (attempts <= 2) {
      try {
        await processJob(message);
        success = true;
        break;
      } catch (error) {
        attempts++;
        lastError = error;
      }
    }

    if (!success) {
      const errorReason = lastError instanceof Error ? lastError.message : String(lastError);

      await writeToDatabase(dlqTable, {
        payload: message,
        error: errorReason,
        timestamp: new Date().toISOString(),
        retryAttempts: attempts - 1
      });

      await sendSlackMessage(
        opsChannel,
        `🚨 Job processing failed after 2 retries. Reason: ${errorReason}`
      );
    }
  }
}
