async function monitorMetricsStream(url: string, intervalMs: number) {
  const stream = pollSource(url, intervalMs);

  for await (const metrics of stream) {
    if (metrics.errorRate > 0.05) {
      const alert = sendPushNotification(`PagerDuty Alert: Error rate has exceeded 5% (Current: ${metrics.errorRate * 100}%)`);
      const audit = logToAudit({
        event: 'High Error Rate Detected',
        errorRate: metrics.errorRate,
        timestamp: new Date().toISOString()
      });
      const dashboard = writeToDatabase('status_dashboard', {
        status: 'Critical',
        errorRate: metrics.errorRate,
        lastUpdated: new Date().toISOString()
      });

      // Promise.allSettled ensures each side effect completes independently 
      // regardless of whether others succeed or fail.
      await Promise.allSettled([alert, audit, dashboard]);
    }
  }
}
