async function handleUserSignup(userData: { email: string; name: string }) {
  const steps = [
    {
      name: 'Email Validation',
      action: async () => {
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        if (!emailRegex.test(userData.email)) {
          throw new Error('Invalid email format');
        }
      }
    },
    {
      name: 'Create User Record',
      action: async () => {
        await writeToDatabase('users', userData);
      }
    },
    {
      name: 'Send Welcome Email',
      action: async () => {
        const verificationLink = `https://app.com/verify?token=${encodeURIComponent(userData.email)}`;
        await sendEmail(
          userData.email,
          'Welcome to our platform!',
          `Please verify your email by clicking here: ${verificationLink}`
        );
      }
    },
    {
      name: 'Enqueue Analytics Event',
      action: async () => {
        await writeToDatabase('analytics_events', {
          event: 'user_signup',
          email: userData.email,
          timestamp: new Date().toISOString()
        });
      }
    },
    {
      name: 'Provision Default Workspace',
      action: async () => {
        await writeToDatabase('workspaces', {
          ownerEmail: userData.email,
          name: 'My Default Workspace',
          createdAt: new Date().toISOString()
        });
      }
    }
  ];

  for (const step of steps) {
    try {
      await step.action();
    } catch (error: any) {
      await logToAudit({
        event: 'signup_step_failure',
        step: step.name,
        error: error.message,
        timestamp: new Date().toISOString()
      });
    }
  }
}
